import sys

def read_numbers():
    line = sys.stdin.readline().strip()
    if not line:
        return []
    return list(map(int, line.split()))

def build_prefix(values):
    prefix = [0]
    total = 0
    for value in values:
        total += value
        prefix.append(total)
    return prefix

def range_sum(prefix, left, right):
    return prefix[right] - prefix[left - 1]

n, q = read_numbers()
nums = read_numbers()
prefix = build_prefix(nums)
l, r = read_numbers()
print(range_sum(prefix, l, r))

def update_run(ch, cur, best):
    if ch == '1':
        cur += 1
        if cur > best:
            best = cur
    else:
        cur = 0
    return cur, best

def solve_case(text, cur, best):
    for ch in text.strip():
        cur, best = update_run(ch, cur, best)
    return cur, best

T = int(input())
best = 0
cur = 0
for _ in range(T):
    s = input().strip()
    cur, best = solve_case(s, cur, best)
    print(best)

n = int(input())
total = 0
for d in range(1, n + 1):
    if n % d == 0:
        total += 1
print(total)
